arguments.argument:
//requires: timeCurr, timeTillOn, timeTillOff
if global.gamePaused=false
{
  if oGame.time mod 2=0
  {
    if image_alpha=1 {image_alpha=0.5}
    else {image_alpha=1}
  }
  
  timeCurr+=1
  if mask_index=sNull
  {
    if timeCurr>=timeTillOn
    {
      mask_index=sPlatTempFade
      timeCurr=0
    }
  }
  else
  {
    if timeCurr>=timeTillOff
    {
      mask_index=sNull
      timeCurr=0
    }
  }
}
